// SLA113 Game Engine — Barrio Runner
// Template: Platformer
// Auto-generated by SLA113 Build Pipeline

const GAME_CONFIG = {
  "type": "platformer",
  "name": "Barrio Runner",
  "version": "1.0.0",
  "built_by": "SLA113"
};
const ASSET_MANIFEST = [];

(async () => {
  const app = new PIXI.Application({ width: window.innerWidth, height: window.innerHeight, backgroundColor: 0x101828, antialias: true });
  document.body.appendChild(app.view);
  document.getElementById('loading').style.display = 'none';
  window.addEventListener('resize', () => app.renderer.resize(window.innerWidth, window.innerHeight));

  const W = app.screen.width, H = app.screen.height;
  let score = 0, coins = 0;
  const keys = {}, G = 0.5;
  document.addEventListener('keydown', e => keys[e.code] = true);
  document.addEventListener('keyup', e => keys[e.code] = false);

  // Platforms
  const platforms = [];
  const platformData = [
    { x: 0, y: H-40, w: W, h: 40 },
    { x: 200, y: H-160, w: 200, h: 20 },
    { x: 500, y: H-280, w: 180, h: 20 },
    { x: 100, y: H-380, w: 150, h: 20 },
    { x: 700, y: H-200, w: 220, h: 20 },
    { x: 400, y: H-440, w: 160, h: 20 },
    { x: 900, y: H-340, w: 200, h: 20 },
  ];
  platformData.forEach(p => {
    const g = new PIXI.Graphics();
    g.beginFill(0x2a2a2a).drawRect(0, 0, p.w, p.h).endFill();
    g.lineStyle(1, 0x444444).drawRect(0, 0, p.w, p.h);
    g.x = p.x; g.y = p.y;
    g.pw = p.w; g.ph = p.h;
    app.stage.addChild(g); platforms.push(g);
  });

  // Coins
  const coinList = [];
  for (let i = 0; i < 8; i++) {
    const c = new PIXI.Graphics();
    c.beginFill(0xd4af37).drawCircle(0, 0, 8).endFill();
    c.beginFill(0xf0d060).drawCircle(0, 0, 5).endFill();
    c.x = 150 + Math.random() * (W-300); c.y = H - 100 - Math.random() * 400;
    c.collected = false;
    app.stage.addChild(c); coinList.push(c);
  }

  // Player
  const player = new PIXI.Graphics();
  player.beginFill(0x00c8ff).drawRect(-12, -20, 24, 40).endFill();
  player.x = 80; player.y = H - 80; player.vx = 0; player.vy = 0; player.grounded = false;
  app.stage.addChild(player);

  app.ticker.add(() => {
    if (keys['KeyA'] || keys['ArrowLeft']) player.vx = -4;
    else if (keys['KeyD'] || keys['ArrowRight']) player.vx = 4;
    else player.vx *= 0.85;
    if ((keys['KeyW'] || keys['ArrowUp'] || keys['Space']) && player.grounded) { player.vy = -12; player.grounded = false; }

    player.vy += G;
    player.x += player.vx; player.y += player.vy;
    player.grounded = false;

    platforms.forEach(p => {
      if (player.x+12>p.x && player.x-12<p.x+p.pw && player.y+20>p.y && player.y+20<p.y+p.ph+10 && player.vy>=0) {
        player.y = p.y - 20; player.vy = 0; player.grounded = true;
      }
    });

    if (player.x < 12) player.x = 12;
    if (player.x > W-12) player.x = W-12;
    if (player.y > H+50) { player.x = 80; player.y = H-80; player.vy = 0; }

    coinList.forEach(c => {
      if (!c.collected && Math.abs(player.x-c.x)<16 && Math.abs(player.y-c.y)<24) {
        c.collected = true; c.visible = false; coins++; score += 100;
        document.getElementById('score').textContent = score;
      }
      if (!c.collected) c.y += Math.sin(Date.now()/300 + c.x) * 0.3;
    });
  });

  console.log('[SLA113] Platformer initialized');
})();
